 1	import { Th } from '@patternfly/react-table';
 2	
 3	import { buildSort } from './sort';
 4	import type { TableViewHeaderProps } from './types';
 5	
 6	const DefaultSelectHeader = <T,>({
 7	  activeSort,
 8	  setActiveSort,
 9	  visibleColumns,
10	}: TableViewHeaderProps<T>) => {
11	  return (
12	    <>
13	      <Th screenReaderText="Row select" />
14	      {visibleColumns.map(({ info, label, resourceFieldId, sortable }, columnIndex) => (
15	        <Th
16	          key={resourceFieldId}
17	          sort={
18	            sortable
19	              ? buildSort({
20	                  activeSort,
21	                  columnIndex,
22	                  resourceFields: visibleColumns,
23	                  setActiveSort,
24	                })
25	              : undefined
26	          }
27	          info={info}
28	        >
29	          {label}
30	        </Th>
31	      ))}
32	    </>
33	  );
34	};
35	
36	export default DefaultSelectHeader;

